import React, { useEffect, useMemo, useState } from 'react';
import api from '../../services/api';
import { showToast } from '../../utils/toast';
import '../../styles/storekeeper/storekeeper-layout.css';
import '../../styles/storekeeper/storekeeper-imports.css';

const INITIAL_FORM = {
  productId: '',
  quantity: '',
  unitPrice: '',
  note: '',
  importDate: new Date().toISOString().split('T')[0],
};

const INITIAL_FILTERS = {
  productId: '',
  productCode: '',
  startDate: '',
  endDate: '',
};

const currencyFormatter = new Intl.NumberFormat('vi-VN', {
  style: 'currency',
  currency: 'VND',
  maximumFractionDigits: 0,
});

const numberFormatter = new Intl.NumberFormat('vi-VN', {
  maximumFractionDigits: 2,
});

const formatCurrency = (value) => currencyFormatter.format(Number(value || 0));
const formatNumber = (value) => numberFormatter.format(Number(value || 0));

const getMonthKey = (value) => {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
};

const getRecentMonths = (count = 6) => {
  const today = new Date();
  today.setDate(1);

  return Array.from({ length: count }, (_, index) => {
    const date = new Date(today);
    date.setMonth(today.getMonth() - (count - index - 1));
    return {
      key: `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`,
      label: date.toLocaleDateString('vi-VN', { month: 'short', year: '2-digit' }),
    };
  });
};

const StorekeeperImports = () => {
  const [imports, setImports] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);

  const [filters, setFilters] = useState(INITIAL_FILTERS);
  const [formData, setFormData] = useState(INITIAL_FORM);

  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);

  useEffect(() => {
    loadProducts();
    loadImports(INITIAL_FILTERS);
  }, []);

  const loadProducts = async () => {
    try {
      const response = await api.get('/inventory/products');
      setProducts(response.data?.data || []);
    } catch (err) {
      console.error('Lỗi tải sản phẩm:', err);
    }
  };

  const loadImports = async (activeFilters = filters) => {
    try {
      setLoading(true);

      const params = new URLSearchParams();
      if (activeFilters.productId) params.append('productId', activeFilters.productId);
      if (activeFilters.startDate) params.append('startDate', activeFilters.startDate);
      if (activeFilters.endDate) params.append('endDate', activeFilters.endDate);

      const response = await api.get(`/inventory/imports?${params.toString()}`);
      setImports(response.data?.data || []);
    } catch (err) {
      showToast({ title: 'Lỗi tải dữ liệu nhập kho', type: 'error' })
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const filteredImports = useMemo(() => {
    const keyword = filters.productCode.trim().toLowerCase();
    return imports.filter((item) => {
      if (!keyword) return true;
      return String(item.product_code || '').toLowerCase().includes(keyword);
    });
  }, [imports, filters.productCode]);

  const totalRecords = filteredImports.length;
  const totalPages = Math.max(1, Math.ceil(totalRecords / pageSize));
  const safeCurrentPage = Math.min(currentPage, totalPages);
  const startIndex = (safeCurrentPage - 1) * pageSize;
  const paginatedImports = filteredImports.slice(startIndex, startIndex + pageSize);

  const totalImportAmount = useMemo(
    () => filteredImports.reduce((sum, row) => sum + Number(row.total_amount || 0), 0),
    [filteredImports]
  );

  const dashboardStats = useMemo(() => {
    const todayKey = new Date().toISOString().slice(0, 10);
    const todayImports = filteredImports.filter((item) => String(item.import_date || '').slice(0, 10) === todayKey).length;
    const totalQuantity = filteredImports.reduce((sum, row) => sum + Number(row.quantity || 0), 0);
    const uniqueProducts = new Set(filteredImports.map((item) => item.product_id || item.product_code)).size;
    const activeImportors = new Set(filteredImports.map((item) => item.created_by_name || ''));
    activeImportors.delete('');

    return {
      totalRecords,
      todayImports,
      totalQuantity,
      uniqueProducts,
      activeImportors: activeImportors.size,
      totalImportAmount,
    };
  }, [filteredImports, totalRecords, totalImportAmount]);

  const monthlyStats = useMemo(() => {
    const months = getRecentMonths(6);
    const buckets = months.map((month) => ({
      ...month,
      count: 0,
      amount: 0,
    }));

    filteredImports.forEach((item) => {
      const monthKey = getMonthKey(item.import_date);
      const bucket = buckets.find((entry) => entry.key === monthKey);
      if (bucket) {
        bucket.count += 1;
        bucket.amount += Number(item.total_amount || 0);
      }
    });

    const maxCount = Math.max(1, ...buckets.map((item) => item.count));

    return buckets.map((item) => ({
      ...item,
      height: Math.max(12, (item.count / maxCount) * 100),
    }));
  }, [filteredImports]);

  const topProducts = useMemo(() => {
    const productMap = new Map();

    filteredImports.forEach((item) => {
      const key = item.product_id || item.product_code || item.product_name || item.import_id;
      const current = productMap.get(key) || {
        key,
        productCode: item.product_code || '-',
        productName: item.product_name || 'Sản phẩm chưa rõ',
        unit: item.unit || '-',
        quantity: 0,
        amount: 0,
      };

      current.quantity += Number(item.quantity || 0);
      current.amount += Number(item.total_amount || 0);
      productMap.set(key, current);
    });

    const items = [...productMap.values()].sort((left, right) => right.amount - left.amount || right.quantity - left.quantity);
    const maxAmount = Math.max(1, ...items.map((item) => item.amount));

    return items.slice(0, 5).map((item) => ({
      ...item,
      width: Math.max(18, (item.amount / maxAmount) * 100),
    }));
  }, [filteredImports]);

  const topOperators = useMemo(() => {
    const operatorMap = new Map();

    filteredImports.forEach((item) => {
      const name = item.created_by_name || 'Không rõ';
      operatorMap.set(name, (operatorMap.get(name) || 0) + 1);
    });

    return [...operatorMap.entries()]
      .map(([name, count]) => ({ name, count }))
      .sort((left, right) => right.count - left.count)
      .slice(0, 4);
  }, [filteredImports]);

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
  };

  const handleFilterSubmit = (e) => {
    e.preventDefault();
    setCurrentPage(1);
    loadImports(filters);
  };

  const handleResetFilters = () => {
    setFilters(INITIAL_FILTERS);
    setCurrentPage(1);
    loadImports(INITIAL_FILTERS);
  };

  const handleOpenModal = () => {
    setFormData(INITIAL_FORM);
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setFormData(INITIAL_FORM);
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (!formData.productId || !formData.quantity || formData.unitPrice === '') {
        showToast({ title: 'Vui lòng nhập đầy đủ sản phẩm, số lượng và đơn giá.', type: 'error' })
        return;
      }

      const payload = {
        productId: Number(formData.productId),
        quantity: Number(formData.quantity),
        unitPrice: Number(formData.unitPrice),
        note: formData.note || null,
        importDate: formData.importDate,
      };

      const response = await api.post('/inventory/imports', payload);
      if (response.data?.success) {
        setFormData(INITIAL_FORM);
        handleCloseModal();
        showToast({ title: 'Tạo phiếu nhập thành công', type: 'success' })
        loadImports(filters);
      }
    } catch (err) {
      showToast({ title: `Lỗi tạo phiếu nhập kho: ${err.response?.data?.message || err.message}`, type: 'error' })
    }
  };

  if (loading) {
    return (
      <div className="storekeeper-imports-container storekeeper-page">
        <div className="loading-spinner">Đang tải dữ liệu nhập kho...</div>
      </div>
    );
  }

  return (
    <div className="storekeeper-imports-container storekeeper-page">
      <section className="storekeeper-imports__hero">
        <div className="storekeeper-imports__hero-copy">
          <span className="storekeeper-imports__eyebrow">Nhập kho</span>
          <h1>Quản lý phiếu nhập hàng</h1>
          <p>Ghi nhận nhập kho, theo dõi biến động số lượng và giá trị theo thời gian.</p>
          <div className="storekeeper-imports__hero-meta">
            <span>{dashboardStats.totalRecords.toLocaleString('vi-VN')} chứng từ</span>
            <span>{dashboardStats.uniqueProducts.toLocaleString('vi-VN')} sản phẩm</span>
            <span>{formatCurrency(dashboardStats.totalImportAmount)}</span>
          </div>
        </div>

        <div className="storekeeper-imports__hero-actions">
          <button className="btn btn-primary storekeeper-imports__primary-action" onClick={handleOpenModal}>
            + Thêm phiếu nhập mới
          </button>
          <button className="btn btn-secondary storekeeper-imports__secondary-action" onClick={handleResetFilters}>
            Đặt lại bộ lọc
          </button>
        </div>
      </section>

      <section className="storekeeper-imports__summary-grid">
        <article className="storekeeper-imports__summary-card storekeeper-imports__summary-card--blue">
          <div className="storekeeper-imports__summary-icon">📦</div>
          <div>
            <span>Tổng phiếu nhập</span>
            <strong>{dashboardStats.totalRecords.toLocaleString('vi-VN')}</strong>
          </div>
        </article>
        <article className="storekeeper-imports__summary-card storekeeper-imports__summary-card--green">
          <div className="storekeeper-imports__summary-icon">🕘</div>
          <div>
            <span>Phiếu nhập hôm nay</span>
            <strong>{dashboardStats.todayImports.toLocaleString('vi-VN')}</strong>
          </div>
        </article>
        <article className="storekeeper-imports__summary-card storekeeper-imports__summary-card--amber">
          <div className="storekeeper-imports__summary-icon">🧮</div>
          <div>
            <span>Tổng số lượng nhập</span>
            <strong>{formatNumber(dashboardStats.totalQuantity)}</strong>
          </div>
        </article>
        <article className="storekeeper-imports__summary-card storekeeper-imports__summary-card--slate">
          <div className="storekeeper-imports__summary-icon">👤</div>
          <div>
            <span>Người nhập hoạt động</span>
            <strong>{dashboardStats.activeImportors.toLocaleString('vi-VN')}</strong>
          </div>
        </article>
      </section>

      <section className="storekeeper-imports__workspace">
        <div className="storekeeper-imports__main-column">
          <div className="storekeeper-imports__panel storekeeper-imports__filters-panel">
            <div className="storekeeper-imports__panel-header">
              <div>
                <h2>Tìm kiếm và lọc</h2>
                <p>Lọc theo mã sản phẩm, sản phẩm và khoảng ngày để xem đúng dữ liệu cần kiểm tra.</p>
              </div>
              <span className="storekeeper-imports__panel-chip">{filteredImports.length.toLocaleString('vi-VN')} kết quả</span>
            </div>

            <form onSubmit={handleFilterSubmit} className="storekeeper-imports__filter-form">
              <div className="storekeeper-imports__filter-grid">
                <div className="form-group">
                  <label>Mã sản phẩm</label>
                  <input
                    name="productCode"
                    value={filters.productCode}
                    onChange={handleFilterChange}
                    className="form-input"
                    placeholder="VD: SP001"
                  />
                </div>

                <div className="form-group">
                  <label>Sản phẩm</label>
                  <select name="productId" value={filters.productId} onChange={handleFilterChange} className="form-input">
                    <option value="">-- Tất cả sản phẩm --</option>
                    {products.map((p) => (
                      <option key={p.product_id} value={p.product_id}>
                        {p.product_code} - {p.product_name}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="form-group">
                  <label>Từ ngày</label>
                  <input type="date" name="startDate" value={filters.startDate} onChange={handleFilterChange} className="form-input" />
                </div>

                <div className="form-group">
                  <label>Đến ngày</label>
                  <input type="date" name="endDate" value={filters.endDate} onChange={handleFilterChange} className="form-input" />
                </div>
              </div>

              <div className="storekeeper-imports__filter-actions">
                <button type="submit" className="btn btn-primary">Lọc dữ liệu</button>
                <button type="button" className="btn btn-secondary" onClick={handleResetFilters}>Đặt lại</button>
              </div>
            </form>
          </div>

          <div className="storekeeper-imports__panel storekeeper-imports__table-panel">
            <div className="storekeeper-imports__panel-header storekeeper-imports__panel-header--table">
              <div>
                <h2>Danh sách phiếu nhập</h2>
                <p>Theo dõi ngày nhập, số lượng, đơn giá và người nhập trực tiếp trong bảng bên dưới.</p>
              </div>
              <button className="btn btn-primary storekeeper-imports__table-action" onClick={handleOpenModal}>
                + Tạo phiếu nhập
              </button>
            </div>

            <div className="storekeeper-imports__table-shell">
              <table className="storekeeper-imports__table">
                <thead>
                  <tr>
                    <th>Ngày nhập</th>
                    <th>Mã sản phẩm</th>
                    <th>Tên sản phẩm</th>
                    <th>Số lượng</th>
                    <th>Đơn vị</th>
                    <th>Đơn giá</th>
                    <th>Thành tiền</th>
                    <th>Người nhập</th>
                    <th>Ghi chú</th>
                  </tr>
                </thead>
                <tbody>
                  {paginatedImports.length === 0 ? (
                    <tr>
                      <td colSpan="9" className="storekeeper-imports__empty-row">Không có dữ liệu phù hợp</td>
                    </tr>
                  ) : (
                    paginatedImports.map((imp) => (
                      <tr key={imp.import_id}>
                        <td>{new Date(imp.import_date).toLocaleDateString('vi-VN')}</td>
                        <td className="storekeeper-imports__mono">{imp.product_code}</td>
                        <td>{imp.product_name}</td>
                        <td className="storekeeper-imports__right">{formatNumber(imp.quantity)}</td>
                        <td>{imp.unit}</td>
                        <td className="storekeeper-imports__right">{formatCurrency(imp.unit_price)}</td>
                        <td className="storekeeper-imports__right storekeeper-imports__strong">{formatCurrency(imp.total_amount)}</td>
                        <td>{imp.created_by_name || '-'}</td>
                        <td className="storekeeper-imports__muted">{imp.note || '-'}</td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            <div className="storekeeper-imports__pagination">
              <div className="storekeeper-imports__pagination-info">
                Hiển thị {totalRecords === 0 ? 0 : startIndex + 1}-{Math.min(startIndex + pageSize, totalRecords)} / {totalRecords}
              </div>
              <div className="storekeeper-imports__pagination-controls">
                <label>
                  Dòng/trang
                  <select
                    value={pageSize}
                    onChange={(e) => {
                      setPageSize(Number(e.target.value));
                      setCurrentPage(1);
                    }}
                  >
                    <option value={10}>10</option>
                    <option value={20}>20</option>
                    <option value={50}>50</option>
                  </select>
                </label>
                <button type="button" className="btn btn-secondary" disabled={safeCurrentPage <= 1} onClick={() => setCurrentPage((page) => Math.max(1, page - 1))}>
                  Trước
                </button>
                <span className="storekeeper-imports__page-indicator">Trang {safeCurrentPage}/{totalPages}</span>
                <button type="button" className="btn btn-secondary" disabled={safeCurrentPage >= totalPages} onClick={() => setCurrentPage((page) => Math.min(totalPages, page + 1))}>
                  Sau
                </button>
              </div>
            </div>
          </div>
        </div>

        <aside className="storekeeper-imports__sidebar">
          <div className="storekeeper-imports__panel storekeeper-imports__chart-panel">
            <div className="storekeeper-imports__panel-header">
              <div>
                <h2>Thống kê 6 tháng</h2>
                <p>Số phiếu nhập gần đây theo từng tháng.</p>
              </div>
            </div>

            <div className="storekeeper-imports__bar-chart">
              {monthlyStats.map((item) => (
                <div key={item.key} className="storekeeper-imports__bar-item">
                  <div className="storekeeper-imports__bar-track">
                    <div className="storekeeper-imports__bar-fill" style={{ height: `${item.height}%` }} />
                  </div>
                  <span>{item.label}</span>
                </div>
              ))}
            </div>

            <div className="storekeeper-imports__chart-footnote">
              {monthlyStats.length ? 'Biểu đồ hiển thị số lượng phiếu nhập theo tháng.' : 'Chưa có dữ liệu để hiển thị biểu đồ.'}
            </div>
          </div>

          <div className="storekeeper-imports__panel storekeeper-imports__top-products-panel">
            <div className="storekeeper-imports__panel-header">
              <div>
                <h2>Top sản phẩm nhập</h2>
                <p>Sản phẩm được nhập nhiều nhất theo giá trị.</p>
              </div>
            </div>

            <div className="storekeeper-imports__top-list">
              {topProducts.length === 0 ? (
                <div className="storekeeper-imports__empty-state">Chưa có dữ liệu sản phẩm.</div>
              ) : (
                topProducts.map((item) => (
                  <div key={item.key} className="storekeeper-imports__top-item">
                    <div className="storekeeper-imports__top-row">
                      <div>
                        <strong>{item.productName}</strong>
                        <p>{item.productCode} · {item.unit}</p>
                      </div>
                      <span>{formatCurrency(item.amount)}</span>
                    </div>
                    <div className="storekeeper-imports__progress">
                      <div className="storekeeper-imports__progress-fill" style={{ width: `${item.width}%` }} />
                    </div>
                    <div className="storekeeper-imports__top-meta">{formatNumber(item.quantity)} đơn vị</div>
                  </div>
                ))
              )}
            </div>
          </div>

          <div className="storekeeper-imports__panel storekeeper-imports__operator-panel">
            <div className="storekeeper-imports__panel-header">
              <div>
                <h2>Người nhập gần đây</h2>
                <p>Những tài khoản đang ghi nhận phiếu nhập nhiều nhất.</p>
              </div>
            </div>

            <div className="storekeeper-imports__operator-list">
              {topOperators.length === 0 ? (
                <div className="storekeeper-imports__empty-state">Chưa có dữ liệu người nhập.</div>
              ) : (
                topOperators.map((item) => (
                  <div key={item.name} className="storekeeper-imports__operator-item">
                    <span>{item.name}</span>
                    <strong>{item.count.toLocaleString('vi-VN')}</strong>
                  </div>
                ))
              )}
            </div>
          </div>
        </aside>
      </section>

      {showModal && (
        <div className="storekeeper-imports__modal" onClick={handleCloseModal}>
          <div className="storekeeper-imports__modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="storekeeper-imports__modal-header">
              <h3>Tạo phiếu nhập kho</h3>
              <button className="storekeeper-imports__close-btn" onClick={handleCloseModal}>
                ×
              </button>
            </div>

            <form onSubmit={handleSubmit}>
              <div className="storekeeper-imports__form-row">
                <div className="form-group">
                  <label>Sản phẩm *</label>
                  <select name="productId" value={formData.productId} onChange={handleFormChange} className="form-input" required>
                    <option value="">-- Chọn sản phẩm --</option>
                    {products.map((p) => (
                      <option key={p.product_id} value={p.product_id}>
                        {p.product_code} - {p.product_name}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="form-group">
                  <label>Ngày nhập *</label>
                  <input type="date" name="importDate" value={formData.importDate} onChange={handleFormChange} className="form-input" required />
                </div>
              </div>

              <div className="storekeeper-imports__form-row">
                <div className="form-group">
                  <label>Số lượng *</label>
                  <input type="number" name="quantity" value={formData.quantity} onChange={handleFormChange} step="0.01" className="form-input" required />
                </div>
                <div className="form-group">
                  <label>Đơn giá *</label>
                  <input type="number" name="unitPrice" value={formData.unitPrice} onChange={handleFormChange} step="0.01" className="form-input" required />
                </div>
              </div>

              <div className="form-group">
                <label>Ghi chú</label>
                <textarea name="note" value={formData.note} onChange={handleFormChange} className="form-input" rows="3" placeholder="Nhập ghi chú nếu cần" />
              </div>

              <div className="storekeeper-imports__modal-actions">
                <button type="button" className="btn btn-secondary" onClick={handleCloseModal}>
                  Hủy
                </button>
                <button type="submit" className="btn btn-primary">Lưu phiếu nhập</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StorekeeperImports;
